export type StockMarket = "nse" | "global";

export interface QuickStockSymbol {
  symbol: string;
  market: StockMarket;
  label?: string;
}

export interface StockListItem {
  ticker: string;
  name: string;
  price: number;
  change: number;
  volume: string;
  marketCap: string;
  sector: string;
  pe: number;
  dividend: number;
  market: StockMarket;
  currency?: string;
}

export interface WatchlistStockItem {
  ticker: string;
  name: string;
  price: string;
  change: string;
  volume: string;
  signal: "Buy" | "Hold" | "Sell";
  isPositive: boolean;
  marketCap: string;
  peRatio: string;
  market: StockMarket;
}

